car_map AS (
  SELECT c.car_id, m.image_path, m.sort_order
  FROM m
  JOIN cars c ON c.brand = m.brand AND c.model = m.model AND c.year = m.year
)
DELETE FROM car_images ci
USING car_map cm
WHERE ci.car_id = cm.car_id;

